var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장, 탄약은 이걸로 끝이야.","JPN":"くそ、これで弾薬は最後だ。","ENG":"Damn, that was my last round.","TWN":"可惡，彈藥就此用盡了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"투척 나이프는 5자루… 겨우 이걸로 녀석들에게서 벗어날 수 있을까……?","JPN":"投げナイフは5本……こんな貧弱な装備で、やつらから逃れられるのか……？","ENG":"Five throwing knives left... Is that really enough to shake them off...?","TWN":"投擲刀只有5把……僅憑這些能從那些傢伙手中逃脫嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 언제까지 뛰어야 하는데요!","JPN":"ライカ、いつまで走ればいいの！","ENG":"Laika, how much longer do we have to run?!","TWN":"萊卡，我們要跑到什麼時候啊！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이제 그 검은 옷 메이드들은 그림자도 안 보인다고요……!","JPN":"さっきの黒いメイドたち、もう影も見えないけど！","ENG":"Those maids in black are long gone...!","TWN":"現在那些黑衣女僕連影子都看不見了……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잔말 말고 계속 뛰기나 해!","JPN":"つべこべ言わずに走れ！","ENG":"Shut up and run!","TWN":"別廢話，繼續跳！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"겨우 이 정도 벗어났다고, 저 집요한 변태들을 따돌릴 수 있을 리가 없잖아……!","JPN":"たったこれぐらいで、あのしつこい変態たちを振り切れると思っちゃだめだ！","ENG":"Just because they're out of sight doesn't mean we're safe. Those obsessive freaks never give up that easily...!","TWN":"才甩開這麼一點，怎麼可能甩掉那些執著的變態啊……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"변태들이라니……?","JPN":"変態たち……？","ENG":"Freaks...?","TWN":"變態們……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"대체 저 메이드들 정체가 뭔데 그래요?","JPN":"あのメイドたち、いったい何なの？","ENG":"Who are those maids anyway?","TWN":"那些女僕到底是什麼來頭？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아, 하아…! 잘 들어, 꼬맹아.","JPN":"はあ、はあ……！　よく聞けよ、おこちゃま。","ENG":"Haha...! Listen up, kid.","TWN":"哈啊，哈啊！聽好了，小鬼。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"언더그라운드… 통칭, 뒷골목에는 잘못 엮였다간, 평생이 피곤해지는 조직이 세 군데 있어.","JPN":"アンダーグラウンド……通称裏路地には、下手に関わったら一生苦労する組織が3つあるんだ。","ENG":"In the Underground—you know, the back alley—there are three names you never want to mess with unless you want a lifetime of regret.","TWN":"地下世界……俗稱後街，有三個組織，一旦牽扯進去，就會一輩子麻煩不斷。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"세 군데라고요?","JPN":"3つ？","ENG":"Three names?","TWN":"三個地方？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"첫 번째는 <color=#ffd34c>성황청의 미친개들</color>…….","JPN":"1つ目は<color=#ffd34c>聖皇庁の狂犬たち</color>……","ENG":"First up, the <color=#ffd34c>Mad Dogs of the Holy Curia</color>...","TWN":"第一個是<color=#ffd34c>聖皇廳的瘋狗們</color>……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이 광신도 자식들이랑 종교 문제로 엮였다간, 지옥 끝까지 쫓아다닌다고.","JPN":"あの狂信徒のやつらと宗教がらみで関わったら、地獄の果てまで追いかけられる。","ENG":"If you ever get tangled up with those zealots over some religious issue, they'll hunt you to the ends of hell.","TWN":"如果和這些狂熱使徒在宗教問題上糾纏不清，他們會追到地獄盡頭。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"성유물 회수, 기적 심사, 이단 심판……. 온갖 그럴싸한 수식어는 다 갖다 붙이지만…….","JPN":"聖遺物の回収、奇跡審査、異端審問……それっぽい単語で飾ってるけど……","ENG":"Holy Relic retrieval, miracle evaluation, heresy trials... They've got a holy name for every shady job.","TWN":"神器回收、奇蹟審查、異端審判……各種聽起來很厲害的詞都用上了……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"결국, 이 자식들의 본질은 종교로 이미지 세탁한 거대 마피아 조직과 다를 바 없거든.","JPN":"結局やつらの本質は、宗教の皮をかぶった巨大マフィア組織なんだ。","ENG":"But when you strip away the robes, they're just a glorified mafia with a Bible in hand.","TWN":"最後，這些傢伙的本質和用宗教洗白自身形象的龐大黑手黨組織沒有什麼區別。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐, 그나마 나은 점은 구색이 종교 집단이라, 그 영역만 건드리지 않으면 녀석들을 마주칠 일은 거의 없다는 거지.","JPN":"まあ、せめてもの救いは……一応宗教団体だから、テリトリーさえ守ればやつらに遭遇することはないってことだな。","ENG":"Fortunately, since they cling to their religious image, you won't see much of them unless you step on their territory.","TWN":"嗯，稍微好一點的是，他們是宗教團體，只要不觸碰到他們的領域，幾乎不會遇到他們。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"두 번째는 <color=#ffd34c>로터스에 사는 벌레들</color>…….","JPN":"2つ目は<color=#ffd34c>ロータスの虫たち</color>……","ENG":"Second, the <color=#ffd34c>bugs that infest Lotus</color>...","TWN":"第二個是<color=#ffd34c>洛德斯裡的蟲子們</color>……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"기억 나? 이쪽은 우리랑도 조금 연이 있는데.","JPN":"覚えてる？　こっちは私たちとも多少縁があるんだけど。","ENG":"Remember? We've had a bit of history with them.","TWN":"記得嗎？這邊和我們也有點關係。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러고보니…….","JPN":"そういえば……","ENG":"Oh, right...","TWN":"我想起來了……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"우리를 도와주었던 초원 씨가 거미 앰블럼을 붙이고 있었죠?","JPN":"私たちを助けてくれたナオさんが、クモのエンブレムをつけてたわね？","ENG":"Chowon, who helped us, was wearing a spider emblem, wasn't she?","TWN":"幫助過我們的初源戴著蜘蛛徽章，對吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래. 거미는 원래 하나의 조직이었는데, 수년 전에 내부 분쟁으로 인해 와해되었지.","JPN":"そう。クモはもともと1つの組織だったけど、数年前に内輪もめで瓦解した。","ENG":"Yeah. The Arachnid used to be one unified organization, but a few years back, they fell apart after some nasty infighting.","TWN":"對。蜘蛛原本是一個組織，但在數年前因內部紛爭而解散了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 뒤로 거미에게 영향을 받아서, 생겨난 점조직들이 로터스에 사는 벌레들이야.","JPN":"その後、クモの後を継ぐようにして立ち上げられた分散型組織群が、ロータスの虫たちさ。","ENG":"All that's left are little offshoots scattered around Lotus, remnants inspired by the Arachnid. The bugs that infest Lotus...","TWN":"之後受到蜘蛛的影響，產生了在洛德斯生活的蟲子們。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"거미가 워낙 막장 집단으로 유명하다 보니, 와해된 뒤에도 여기저기서 이름이 들리더라고.","JPN":"クモの悪名が高いから、瓦解した後もあちこちから名前を聞くんだよね。","ENG":"The Arachnid's name was so infamous that even after the group collapsed, the name kept popping up.","TWN":"因為蜘蛛是出了名的混亂組織，所以即使解散了，到處還是能聽到他們的名字"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"물론, 그중 대부분은 이름이나 빌린 짝퉁들이지만…….","JPN":"もちろん、ほとんどは名ばかりの偽物だけど……","ENG":"Of course, most of them now are just cheap knock-offs riding on the brand.","TWN":"當然，其中大部分都是借來的假名或仿冒品……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 마지막이 저 <color=#ffd34c>맨션의 메이드들</color>이야.","JPN":"そして最後が、あの<color=#ffd34c>マンションのメイドたち</color>だ。","ENG":"And last up are those <color=#ffd34c>Mansion's maids</color>.","TWN":"還有最後是那<color=#ffd34c>曼森的女僕們</color>。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"요인 암살 및 납치, 인신매매, 불법 약물 제조와 유통…….","JPN":"要人の暗殺と拉致、人身売買、違法薬物の製造や流通……","ENG":"Assassinations, kidnappings, human trafficking, illegal drug production and distribution...","TWN":"要人暗殺及綁架、人口販賣、非法藥物製造和流通……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뒷골목에서 발생하는 온갖 더러운 일을 도맡아서 처리하는 청부 조직이지.","JPN":"裏社会で発生するあらゆる汚れ仕事が、依頼という形でやつらに流れ着く。","ENG":"They're a contract syndicate that handles all the filth the back alley has to offer.","TWN":"是一個專門處理後街發生的各種骯髒事情的徵才組織。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"잠깐 메이드라고요……?","JPN":"ちょっと、メイドたちって……？","ENG":"Wait, maids...?","TWN":"等一下，女僕……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼, 지금 우리를 쫓는 게 그 맨션이라는 조직이에요?","JPN":"じゃあ、今私たちを追って来てるのがあのマンションって組織なの？","ENG":"You're saying the organization chasing us is the Mansion?","TWN":"那麼，現在追我們的就是那個名為曼森的組織嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래. 맨션 구성원들의 특징은 전원 여성에다가, 메이드복 차림이거든.","JPN":"そう。マンションの構成員の特徴は、全員女性でメイド服を着てるってこと。","ENG":"Exactly. Every member of the Mansion is a woman, and they all wear maid uniforms.","TWN":"對。公館成員的特點是全員女性，而且都穿著女僕裝。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"조직원 대부분은 어렸을 때부터 약물과 세뇌에 절여져 철저하게 메이드 교육을 받으니까.","JPN":"組織員のほとんどは子供の頃から薬漬けにされたり洗脳されたりして、徹底的にメイドとして教育を受けるんだ。","ENG":"Most of them were drugged and brainwashed from childhood, molded into the \\"perfect maid\\" through brutal training.","TWN":"組織成員大多數從小就被藥物和洗腦徹底浸染，接受嚴格的女僕教育。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그게 마스터라고 불리는 녀석의 고약하고 변태적인 취향이지.","JPN":"マスターって呼ばれてるやつの変態的で醜い趣味でね。","ENG":"All thanks to their so-called Master's messed-up, twisted tastes.","TWN":"那就是被稱為主人的傢伙的惡劣變態的品味。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터에 대한 험담은 메이드로서 금기사항입니다만…….","JPN":"マスターの悪口はメイドとして許しがたい禁忌事項ですが……","ENG":"Talking badly about Master is strictly forbidden among maids...","TWN":"作為女僕，詆毀主人是禁忌……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"엇? 뭐야, 언제부터……!?","JPN":"はっ！？　くっ、いつから！","ENG":"Huh? When did you get here?!","TWN":"咦？什麼，從什麼時候開始……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"목표 확인.","JPN":"ターゲット確認。","ENG":"Target confirmed.","TWN":"確認目標。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"지금부터 당신들을 조용히 납치하겠습니다.","JPN":"今から貴方たちを静かに拉致します。","ENG":"Now then, let's begin your quiet kidnapping.","TWN":"從現在開始我要悄悄地綁架你們。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장, 이 새끼가! 웃기지 말라고……!","JPN":"くっそ、こいつ！　ふざけんな……！","ENG":"Screw you! Like I'd go down that easy...!","TWN":"可惡，你這混蛋！別開玩笑了……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"휘두르는 동작이 너무 크군요. 이쪽이 비었습니다.","JPN":"振り回す動きが大きすぎますね。こちら側ががら空きです。","ENG":"Your swings are too wide. You left yourself open.","TWN":"揮動的動作太大了。這邊空了。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"크읏!?","JPN":"くっ！？","ENG":"Kgh?!","TWN":"呃？！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"커헉……! 제기랄!","JPN":"かはっ……！　ちくしょう！","ENG":"Ack! Damn it!","TWN":"咳呵……！該死！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카!","JPN":"ライカ！","ENG":"Laika!","TWN":"萊卡！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"당신을 에스코트하는 건 접니다.","JPN":"貴方をエスコートするのは私です。","ENG":"I'll be handling your escort personally.","TWN":"由我來護送你。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어, 어느 틈에……!?","JPN":"い、いつの間に……！？","ENG":"W-when did you get behind me...?!","TWN":"什，什麼時候……？！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"크으윽……!","JPN":"くうっ……！","ENG":"Urrrghhh...!","TWN":"呃……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터께서는 당신의 방패를 주의하라 하셨습니다.","JPN":"マスターは貴方の盾に注意しろとおっしゃいました。","ENG":"Master specifically warned me about your shield.","TWN":"主人說要注意你的盾牌。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"따라서 이건 압류하겠습니다.","JPN":"よって、これは没収します。","ENG":"So I'll be confiscating this.","TWN":"因此我要沒收這個。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"펠리세트……!","JPN":"フェリセット……！","ENG":"Félicette...!","TWN":"費莉塞特……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"제기랄, 이거 놔! 이 개자식들아……!","JPN":"くそ、放せ！　このくそったれども……！","ENG":"Let go of me! You sick freaks!","TWN":"該死，放開我！你們這些傢伙……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"제법 저항이 거세군요.","JPN":"抵抗が激しいですね。","ENG":"Quite the feisty one, aren't you?","TWN":"抵抗還挺激烈的呢。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터께서 살려두라 지시하셨으니, 대신 어깨를 뽑겠습니다.","JPN":"マスターから生捕りするようにとの指示を受けていますので、代わりに肩を外させていただきます。","ENG":"Master ordered that you be kept alive. So I'll settle for dislocating your shoulder.","TWN":"既然主人吩咐要留你一命，那我就卸掉你的肩膀吧。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"통증이 있을 겁니다. 참으세요.","JPN":"少し痛みます。我慢してください。","ENG":"This will hurt. Please endure it.","TWN":"會有疼痛，請忍耐。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"으아아아아악……!! 읍읍!!","JPN":"うああああっ……！！　うぶっ！！","ENG":"Aaaaagh! Mmph!","TWN":"額啊啊啊啊……！嗚嗚！！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"쉿. 조용히.","JPN":"しーっ、お静かに。","ENG":"Hush. Quiet now.","TWN":"噓，你們兩個都停一下。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"제 임무는 당신들을 조용히 납치하는 겁니다. 그러니 입을 닫아 드리죠.","JPN":"私の任務は貴方たちを静かに拉致することです。なので口を塞いで差し上げましょう。","ENG":"My mission is to abduct you quietly, so let's take care of that mouth.","TWN":"我的任務是悄悄綁架你們，所以我會讓你們閉嘴。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"더 시끄럽게 군다면, 혀를 자르겠습니다.","JPN":"これ以上騒がしくすれば、舌を切ります。","ENG":"If you get any louder, I'll remove your tongue.","TWN":"再吵的話，我就割掉你的舌頭。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"읍!! 읍읍……!!","JPN":"うっ！！　うぶぶっ……！！","ENG":"Mmph! Mmmmm!","TWN":"唔！唔唔……！！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE","text":{"KOREA":"보기가 안쓰럽구나. 그쯤 해두렴.","JPN":"見るに堪えないわね。その辺にしておきなさい。","ENG":"This is hard to watch. That's enough.","TWN":"看起來真可憐。就到此為止吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터……?","JPN":"マスター……？","ENG":"Master...?","TWN":"頭目……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이런 미친……!","JPN":"そんなバカな……！","ENG":"You've gotta be kidding me...!","TWN":"這瘋子……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"설마… 고작 우리를 낚으려고, 이정도의 인원이 매복하고 있었다고……?","JPN":"まさか……私たちを捕まえるためだけに、これだけの人数に待ち伏せさせていたのか……？","ENG":"Don't tell me... they had this many people lying in wait just to catch us...?","TWN":"難道……只是為了引誘我們，就埋伏了這麼多人……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"잠깐만요, 라이카.","JPN":"待って、ライカ。","ENG":"Hold on, Laika.","TWN":"等一下，萊卡。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저 사람들 얼굴… 어디서 많이 본 것 같은데……?","JPN":"あの人たちの顔……見覚えがあるわ……？","ENG":"Those faces... I feel like I've seen them somewhere before.","TWN":"那些人的臉……好像在哪裡見過……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"블랙 로즈 1개 분대.","JPN":"ブラックローズ第1分隊。","ENG":"One squad of Black Rose.","TWN":"黑玫瑰1個分隊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L16_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"지시하신 대로 목표 두 사람의 신병을 확보하였습니다.","JPN":"ご指示通り、ターゲット2人の身柄を確保いたしました。","ENG":"As ordered, we have secured the two targets.","TWN":"按照指示，我已經抓獲了兩個目標。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터, 칭찬을.","JPN":"マスター、お褒めの言葉を。","ENG":"Requesting praise, Master.","TWN":"主人，誇獎我吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"조금 소란스럽긴 했다만…….","JPN":"少し騒がしいところはあったけど……","ENG":"It got a bit noisy, but...","TWN":"雖然有點吵鬧……"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래, 첫 실전치고는 꽤나 만족스러운 성과구나.","JPN":"そうね、初実戦にしてはよくやったわ。","ENG":"But for a first mission, I'd say it went quite well.","TWN":"嗯，作為第一次實戰，這個成果相當令人滿意。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"……감사합니다.","JPN":"……ありがとうございます。","ENG":"...Thank you.","TWN":"……謝謝。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그건 그렇고…….","JPN":"それはそうとして……","ENG":"Anyway...","TWN":"不過說起來……"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"오랜만이구나, 쿠드랴프카.","JPN":"久しぶりね、クドリャフカ。","ENG":"Long time no see, Kudryavka.","TWN":"好久不見，庫德里亞夫卡。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"오랜만은 개뿔……!","JPN":"ざけんな……！","ENG":"Long time my ass–!","TWN":"見鬼的好久不見……！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"크아아아악……!","JPN":"くわあああ……！","ENG":"Aaargh...!","TWN":"啊啊啊啊啊……！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L34_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터께 언행을 주의하세요.","JPN":"マスターの前では口を慎んでください。","ENG":"Mind your words when speaking to Master.","TWN":"注意對主人的言行。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"로즈, 내가 그쯤 해두라고 했을 텐데?","JPN":"ローズ、その辺にしておきなさいと言ったはずよ。","ENG":"Rose. I told you that was enough.","TWN":"我不是說過到此為止了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"죄송합니다. 마스터.","JPN":"申し訳ございません、マスター。","ENG":"My apologies, Master.","TWN":"對不起，主人。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"일으켜 세워.","JPN":"立たせて。","ENG":"Get her on her feet.","TWN":"站起來。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"원래라면, 내 정원을 거처 간 잡초들에게는 그다지 관심 주지 않는 편이지만.","JPN":"本来は、私の庭園を通った雑草にはあまり興味を持たない主義だけど……","ENG":"I usually pay no mind to the weeds that passed through my garden.","TWN":"本來，我對經過我花園的雜草並不怎麼關心。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L47_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래도 너는 꽤 기억에 남는 단다, 쿠드랴프카.","JPN":"あなたは結構印象に残っているのよ、クドリャフカ。","ENG":"But you... you left quite the impression, Kudryavka.","TWN":"不過你還是讓我印象深刻，庫德里亞夫卡。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L48_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"특히, 못 써먹을 잡초 주제에 그 건방진 눈빛이 말이야.","JPN":"特に、役に立たない雑草のくせに生意気な目つきをしているところがね。","ENG":"Especially that arrogant glare... so bold for such a useless little weed.","TWN":"特別是，明明是沒用的雜草，卻有著那種傲慢的眼神。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"큭큭… 엿이나 잡수셔…….","JPN":"くくっ……くそくらえだ、バーカ。","ENG":"Haha... Damn you...","TWN":"呵呵……算了吧……"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"커헉!","JPN":"がはっ！","ENG":"Kuh!","TWN":"咳咳！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L2_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"호출 부호… 쿠드랴프카…….","JPN":"コードネーム……クドリャフカ……","ENG":"Code name... Kudryavka...","TWN":"呼叫代號……庫德里亞夫卡……"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"아무리 생각해도 입에 착 안 달라붙은 호칭이라니까.","JPN":"どうもしっくりこない呼び方なのよね。","ENG":"I've never liked the way that name sounds.","TWN":"無論怎麼想，這個稱呼都不太順口。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"역시 너 같은 잡초에게 어울리는 이름은 그 후보생 시절에 불러주던 호칭이 좋겠지?","JPN":"やっぱり、あなたのような雑草には、候補生時代の呼び方がお似合いね？","ENG":"A weed like you deserves the name we used to call you back during training?","TWN":"果然，像你這樣的雜草，還是叫你候補生時期的稱呼比較合適吧？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"안 그래, <color=#ffd34c>강아지풀</color>……?","JPN":"そうでしょう？　<color=#ffd34c>エノコログサ</color>……","ENG":"Don't you agree... <color=#ffd34c>Bristlegrass</color>...?","TWN":"不是嗎，<color=#ffd34c>狗尾草</color>……？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};